const data = $input.first().json.body;
const staticData = $getWorkflowStaticData('global');

if (!staticData.incidencias) staticData.incidencias = [];

// Modo consulta
if (data.accion === 'consultar') {
  let resultados = staticData.incidencias;
  if (data.curso) resultados = resultados.filter(i => i.curso === data.curso);
  if (data.alumno) resultados = resultados.filter(i =>
    i.alumno.toLowerCase().includes(data.alumno.toLowerCase())
  );
  if (data.tipo) resultados = resultados.filter(i => i.tipo === data.tipo);

  const resumen = {
    total: resultados.length,
    por_tipo: {
      leve: resultados.filter(i => i.tipo === 'leve').length,
      grave: resultados.filter(i => i.tipo === 'grave').length,
      muy_grave: resultados.filter(i => i.tipo === 'muy_grave').length
    }
  };
  return [{ json: { status: 'ok', resumen, incidencias: resultados } }];
}

// Modo borrar todo (solo para administradores)
if (data.accion === 'borrar_todo' && data.confirmar === true) {
  const total = staticData.incidencias.length;
  staticData.incidencias = [];
  return [{ json: { status: 'ok', mensaje: `Se han borrado ${total} incidencias` } }];
}

// Validar campos obligatorios
if (!data.alumno || !data.curso || !data.tipo || !data.descripcion || !data.reportado_por) {
  return [{ json: {
    status: 'error',
    mensaje: 'Campos obligatorios: alumno, curso, tipo (leve/grave/muy_grave), descripcion, reportado_por'
  } }];
}

const tipos_validos = ['leve', 'grave', 'muy_grave'];
if (!tipos_validos.includes(data.tipo)) {
  return [{ json: {
    status: 'error',
    mensaje: 'Tipo debe ser: leve, grave o muy_grave'
  } }];
}

const incidencia = {
  id: staticData.incidencias.length + 1,
  alumno: data.alumno,
  curso: data.curso,
  tipo: data.tipo,
  descripcion: data.descripcion,
  reportado_por: data.reportado_por,
  fecha: new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' })
};

staticData.incidencias.push(incidencia);
return [{ json: { status: 'ok', mensaje: 'Incidencia registrada', incidencia } }];
